31	static int insert_oid_pair(kh_oid_map_t *map, const struct object_id *key, const struct object_id *value)
32	{
33		khiter_t pos;
34		int ret;
35		struct object_id *stored;
36	
37		pos = kh_put_oid_map(map, *key, &ret);
38	
39		/* This item already exists in the map. */
